# --- src/backend/model.py ---
from langchain.chains import LLMChain
from langchain.llms.fake import FakeListLLM
from langchain.prompts import PromptTemplate

def _build_chain():
    prompt = PromptTemplate(
        input_variables=["input"],
        template="You are a helpful assistant. Echo the user input: {input}"
    )
    # Fake LLM that simply returns the formatted string.
    fake_llm = FakeListLLM(responses=["Sure, here's what you said: {input}"])
    return LLMChain(prompt=prompt, llm=fake_llm)

_chain = _build_chain()

def get_response(user_input: str) -> str:
    """Run the LangChain chain and return the assistant's reply."""
    return _chain.run(user_input)

