import React, { useState } from 'react';
import { sendMessage } from './api.js';

export default function App() {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!input.trim()) return;
    const userMsg = { role: 'user', content: input };
    setMessages((prev) => [...prev, userMsg]);
    setInput('');
    setLoading(true);
    try {
      const reply = await sendMessage(userMsg.content);
      const botMsg = { role: 'assistant', content: reply };
      setMessages((prev) => [...prev, botMsg]);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ maxWidth: '600px', margin: '2rem auto', fontFamily: 'sans-serif' }}>
      <h1>LangChain Chat</h1>
      <div style={{ border: '1px solid #ccc', padding: '1rem', minHeight: '200px' }}>
        {messages.map((msg, idx) => (
          <p key={idx} style={{ textAlign: msg.role === 'user' ? 'right' : 'left' }}>
            <strong>{msg.role}:</strong> {msg.content}
          </p>
        ))}
        {loading && <p><em>Thinking...</em></p>}
      </div>
      <form onSubmit={handleSubmit} style={{ marginTop: '1rem' }}>
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Type a message..."
          style={{ width: '80%', padding: '0.5rem' }}
        />
        <button type="submit" style={{ padding: '0.5rem 1rem' }} disabled={loading}>
          Send
        </button>
      </form>
    </div>
  );
}

# --- src/frontend/src/api.js ---
export async function sendMessage(message) {
  const response = await fetch('/api/chat', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({ message })
  });
  if (!response.ok) {
    const err = await response.json();
    throw new Error(err.detail || 'Error from server');
  }
  const data = await response.json();
  return data.reply;
}

